from Crypto.Util.number import *
from math import gcd

# 扩展欧几里得算法
def extended_gcd(a, b):
    if b == 0:
        return (1, 0)
    else:
        x1, y1 = extended_gcd(b, a % b)
        x, y = y1, x1 - (a // b) * y1
        return (x, y)

# 共模攻击主函数
def common_modulus_attack(c1, c2, e1, e2, N):
    # 计算 s1 和 s2，使得 s1*e1 + s2*e2 = 1
    s1, s2 = extended_gcd(e1, e2)
    
    # 如果 s1 为负数，需要计算 c1 的模反元素
    if s1 < 0:
        c1 = inverse(c1, N)
        c1 = pow(c1, -s1, N)
    else:
        c1 = pow(c1, s1, N)

    # 同理处理 c2
    if s2 < 0:
        c2 = inverse(c2, N)
        c2 = pow(c2, -s2, N)
    else:
        c2 = pow(c2, s2, N)

    # 最终的明文
    m = (c1 * c2) % N
    return m

